import { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "../api/axios";

export default function PaymentPage() {
    const { bookingId } = useParams();
    const navigate = useNavigate();
    const [booking, setBooking] = useState(null);
    const [loading, setLoading] = useState(false);
    const [paymentMethod, setPaymentMethod] = useState("UPI");

    useEffect(() => {
        // Fetch booking details (optional, or pass via state)
        // For now, we'll trust the ID and just show a generic amount or fetch if needed.
        // Let's mock the amount for simplicity or fetch it.
        // Real implementation would fetch /api/bookings/:id
    }, [bookingId]);

    const handlePayment = async () => {
        setLoading(true);

        // Simulate Gateway Delay
        setTimeout(async () => {
            try {
                // Generate Mock Transaction ID
                const transactionId = "TXN" + Date.now() + Math.floor(Math.random() * 1000);
                const qrCodeData = `PARKSENSE:${bookingId}:${transactionId}:PAID`; // Simple data for QR

                await axios.post("/bookings/confirm-payment", {
                    bookingId,
                    paymentDetails: {
                        method: paymentMethod,
                        transactionId
                    },
                    qrCode: qrCodeData
                });

                setLoading(false);
                navigate(`/receipt/${bookingId}`);
            } catch (err) {
                console.error("Payment Failed", err);
                setLoading(false);
                alert("Payment Verification Failed");
            }
        }, 2000); // 2 second delay for realism
    };

    return (
        <div className="auth-container">
            <div className="auth-card" style={{ maxWidth: "450px", width: "100%", textAlign: "center" }}>
                <h2 className="auth-title">Secure Checkout</h2>

                <div style={{ background: "rgba(0, 255, 136, 0.1)", padding: "20px", borderRadius: "15px", marginBottom: "25px", border: "1px dashed var(--accent-green)", boxShadow: "var(--shadow-neon-green)" }}>
                    <p style={{ margin: "0", color: "var(--accent-green)", fontWeight: "bold", fontSize: "1.2em", letterSpacing: "2px" }}>BOOKING: {bookingId.slice(-6).toUpperCase()}</p>
                </div>

                <p style={{ textAlign: "left", marginBottom: "15px", fontWeight: "bold", color: "var(--text-secondary)" }}>Select Payment Gateway:</p>
                <div style={{ display: "flex", gap: "15px", marginBottom: "30px" }}>
                    <button
                        onClick={() => setPaymentMethod("UPI")}
                        style={{ ...methodStyle, background: paymentMethod === "UPI" ? "rgba(0, 240, 255, 0.15)" : "var(--bg-tertiary)", borderColor: paymentMethod === "UPI" ? "var(--accent-cyan)" : "rgba(255,255,255,0.1)", color: paymentMethod === "UPI" ? "var(--accent-cyan)" : "var(--text-secondary)", boxShadow: paymentMethod === "UPI" ? "var(--shadow-neon-cyan)" : "none" }}
                    >
                        📱 UPI / QR
                    </button>
                    <button
                        onClick={() => setPaymentMethod("Card")}
                        style={{ ...methodStyle, background: paymentMethod === "Card" ? "rgba(255, 42, 95, 0.15)" : "var(--bg-tertiary)", borderColor: paymentMethod === "Card" ? "var(--accent-pink)" : "rgba(255,255,255,0.1)", color: paymentMethod === "Card" ? "var(--accent-pink)" : "var(--text-secondary)", boxShadow: paymentMethod === "Card" ? "var(--shadow-neon-pink)" : "none" }}
                    >
                        💳 CARD
                    </button>
                </div>

                <button
                    onClick={handlePayment}
                    disabled={loading}
                    className="btn-primary"
                    style={{ width: "100%", padding: "18px", fontSize: "1.1em", letterSpacing: "2px" }}
                >
                    {loading ? "INITIALIZING TRANSFER..." : `CONFIRM PAYMENT`}
                </button>

                <p style={{ marginTop: "25px", fontSize: "0.85em", color: "var(--text-secondary)", letterSpacing: "1px" }}>
                    🔒 256-BIT QUANTUM ENCRYPTION
                </p>
            </div>
        </div>
    );
}

const methodStyle = {
    flex: 1, padding: "15px", border: "1px solid", borderRadius: "12px", cursor: "pointer", fontWeight: "bold", transition: "var(--transition)", letterSpacing: "1px"
};
